const response = items[0].json;
const documents = response.analyzeResult?.documents || [];

const isInvoiceOrReceipt = documents.some(doc => {
  const docType = doc.docType || '';
  const confidence = doc.confidence || 0;
  return (
    (docType.toLowerCase().includes('invoice') || docType.toLowerCase().includes('receipt')) &&
    confidence > 0.5
  );
});

const hasInvoiceFields = documents.some(doc => {
  const fields = doc.fields || {};
  return fields.VendorName || fields.InvoiceId || fields.InvoiceTotal;
});

return [{ json: { ...response, isValidInvoice: isInvoiceOrReceipt || hasInvoiceFields } }];

const response = items[0].json;
const documents = response.analyzeResult?.documents || [];
if (documents.length === 0) throw new Error('No documents found');

const doc = documents[0];
const fields = doc.fields || {};

function getFieldValue(field) {
  if (!field) return null;
  if (field.content) return field.content;
  if (field.valueString) return field.valueString;
  if (field.valueNumber) return field.valueNumber;
  if (field.valueDate) return field.valueDate;
  if (field.valueCurrency) return field.valueCurrency.amount;
  return null;
}

const lineItems = [];
if (fields.Items?.valueArray) {
  fields.Items.valueArray.forEach(item => {
    const f = item.valueObject || {};
    lineItems.push({
      description: getFieldValue(f.Description),
      quantity: getFieldValue(f.Quantity),
      unit_price: getFieldValue(f.UnitPrice),
      amount: getFieldValue(f.Amount)
    });
  });
}

return [{ json: {
  vendor_name: getFieldValue(fields.VendorName),
  invoice_number: getFieldValue(fields.InvoiceId),
  invoice_date: getFieldValue(fields.InvoiceDate),
  due_date: getFieldValue(fields.DueDate),
  total_amount: getFieldValue(fields.InvoiceTotal),
  line_items: lineItems,
  confidence: doc.confidence
}}];
